DELETE FROM dbo.rental WHERE user_id IN (SELECT id FROM dbo.[user] WHERE username LIKE 'testuser_%');
DELETE FROM dbo.scooter WHERE serial_number LIKE 'SN-%';
DELETE FROM dbo.[user] WHERE username LIKE 'testuser_%';
DELETE FROM dbo.location WHERE name LIKE 'Station_%';
